"use client";

import React, { useState } from "react";
import { UploadZone } from "@/components/UploadZone";
import { RiskMeter } from "@/components/RiskMeter";
import { RoadmapTimeline, TimelineItem } from "@/components/RoadmapTimeline";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { motion, AnimatePresence } from "framer-motion";
import { Download, Printer } from "lucide-react";

export default function DashboardPage() {
    const [isProcessing, setIsProcessing] = useState(false);
    const [analysisComplete, setAnalysisComplete] = useState(false);
    const [analysisData, setAnalysisData] = useState<any>(null);

    const handleUpload = async (file: File) => {
        setIsProcessing(true);
        try {
            const formData = new FormData();
            formData.append("file", file);

            const response = await fetch("/api/analyze-contract", {
                method: "POST",
                body: formData,
            });

            if (!response.ok) {
                throw new Error("Failed to analyze contract");
            }

            const data = await response.json();
            setAnalysisData(data.analysis || data);
            setAnalysisComplete(true);
        } catch (error: any) {
            console.error("Upload error:", error);
            alert(error.message || "An error occurred while analyzing the document.");
        } finally {
            setIsProcessing(false);
        }
    };

    const handleExportJSON = () => {
        if (!analysisData) return;
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(analysisData, null, 2));
        const downloadAnchorNode = document.createElement("a");
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "scope_shield_analysis.json");
        document.body.appendChild(downloadAnchorNode); // required for firefox
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    const handleExportCSV = () => {
        if (!analysisData?.tasks) return;
        const tasks = analysisData.tasks;
        const csvRows = [];

        // Headers
        csvRows.push(["ID", "Title", "Type", "Status", "Description"].join(","));

        // Rows
        for (const task of tasks) {
            const row = [
                task.id,
                `"${task.title.replace(/"/g, '""')}"`,
                task.type,
                task.status,
                `"${task.description.replace(/"/g, '""')}"`
            ];
            csvRows.push(row.join(","));
        }

        const csvString = csvRows.join("\n");
        const dataStr = "data:text/csv;charset=utf-8," + encodeURIComponent(csvString);
        const downloadAnchorNode = document.createElement("a");
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "scope_shield_tasks.csv");
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    return (
        <div className="space-y-8 pb-12">
            {!analysisComplete ? (
                <div className="relative">
                    <AnimatePresence mode="popLayout">
                        {isProcessing ? (
                            <motion.div
                                key="loading-skeleton"
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="space-y-8 w-full"
                            >
                                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                                    <div className="space-y-2">
                                        <Skeleton className="h-8 w-48" />
                                        <Skeleton className="h-4 w-64" />
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <Skeleton className="h-14 w-32 rounded-xl" />
                                        <Skeleton className="h-10 w-40 rounded-lg" />
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                    <div className="lg:col-span-1 border border-slate-200 dark:border-slate-800 rounded-2xl p-6 h-full flex flex-col justify-between">
                                        <Skeleton className="h-6 w-3/4 mx-auto mb-6" />
                                        <div className="flex justify-center flex-1 items-center">
                                            <Skeleton className="h-32 w-32 rounded-full" />
                                        </div>
                                        <Skeleton className="h-10 w-full rounded-full mt-6" />
                                    </div>
                                    <div className="lg:col-span-2 border border-slate-200 dark:border-slate-800 rounded-2xl p-8 space-y-8">
                                        <div className="flex justify-between">
                                            <Skeleton className="h-6 w-1/3" />
                                            <Skeleton className="h-6 w-24 rounded-full" />
                                        </div>
                                        <div className="space-y-6">
                                            {[1, 2, 3].map((i) => (
                                                <div key={i} className="flex gap-4">
                                                    <Skeleton className="h-12 w-12 rounded-full shrink-0" />
                                                    <div className="space-y-2 flex-1">
                                                        <Skeleton className="h-5 w-1/2" />
                                                        <Skeleton className="h-4 w-full" />
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </motion.div>
                        ) : (
                            <motion.div
                                key="uploading"
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -20 }}
                                className="flex flex-col items-center justify-center py-12"
                            >
                                <div className="text-center mb-8 max-w-xl">
                                    <h2 className="text-3xl font-bold mb-4">Analyze a New Contract</h2>
                                    <p className="text-slate-600 dark:text-slate-400">
                                        Upload your freelance agreement, statement of work, or contract. We'll automatically identify deliverables, payment milestones, and flag potential scope creep risks.
                                    </p>
                                </div>
                                <UploadZone onUpload={handleUpload} isProcessing={isProcessing} />
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            ) : (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="space-y-8"
                >
                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                        <div>
                            <h2 className="text-2xl font-bold">Analysis Results</h2>
                            <p className="text-slate-500">Website_Redesign_Agreement_v2.pdf</p>
                        </div>

                        <div className="flex flex-col sm:flex-row items-end sm:items-center gap-4">
                            <div className="flex items-center gap-2 mr-2">
                                <Button variant="outline" size="sm" onClick={handleExportCSV} className="gap-2">
                                    <Download className="h-4 w-4" /> CSV
                                </Button>
                                <Button variant="outline" size="sm" onClick={handleExportJSON} className="gap-2">
                                    <Download className="h-4 w-4" /> JSON
                                </Button>
                                <Button variant="outline" size="sm" onClick={() => window.print()} className="gap-2">
                                    <Printer className="h-4 w-4" /> Print
                                </Button>
                            </div>

                            <div className="flex flex-col items-end px-4 py-2 bg-emerald-50 border border-emerald-100 dark:bg-emerald-900/20 dark:border-emerald-900/50 rounded-xl">
                                <span className="text-xs font-semibold uppercase tracking-wider text-emerald-600 dark:text-emerald-400">Value Protected</span>
                                <span className="text-xl font-bold text-emerald-700 dark:text-emerald-500">
                                    ${((analysisData?.tasks?.length || 0) * 1500).toLocaleString()}
                                </span>
                            </div>
                            <Button
                                variant="default"
                                onClick={() => setAnalysisComplete(false)}
                            >
                                Analyze Another PDF
                            </Button>
                        </div>
                    </div>

                    {/* This is where the RiskMeter and Timeline will go */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-1">
                            <RiskMeter score={analysisData?.riskScore || 0} alerts={analysisData?.alerts || []} />
                        </div>
                        <div className="lg:col-span-2">
                            <RoadmapTimeline items={analysisData?.tasks || []} />
                        </div>
                    </div>
                </motion.div>
            )}
        </div>
    );
}

"use client";

import React from "react";
import { motion } from "framer-motion";
import { CheckCircle2, Circle, Clock, CreditCard, Box } from "lucide-react";

export type TimelineItem = {
    id: string;
    title: string;
    description: string;
    type: "deliverable" | "payment" | "milestone";
    status: "completed" | "in_progress" | "pending";
};

interface RoadmapTimelineProps {
    items: TimelineItem[];
}

export function RoadmapTimeline({ items }: RoadmapTimelineProps) {
    const getIcon = (type: TimelineItem["type"], status: TimelineItem["status"]) => {
        if (status === "completed") return <CheckCircle2 className="h-5 w-5 text-emerald-500" />;

        switch (type) {
            case "payment":
                return <CreditCard className={`h-5 w-5 ${status === "in_progress" ? "text-indigo-500" : "text-slate-400"}`} />;
            case "deliverable":
                return <Box className={`h-5 w-5 ${status === "in_progress" ? "text-indigo-500" : "text-slate-400"}`} />;
            default:
                return <Circle className={`h-5 w-5 ${status === "in_progress" ? "text-indigo-500" : "text-slate-400"}`} />;
        }
    };

    return (
        <div className="bg-white dark:bg-slate-950 rounded-2xl border border-slate-200 dark:border-slate-800 p-8 shadow-sm h-full overflow-y-auto">
            <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-semibold text-slate-800 dark:text-slate-200">Task Roadmap</h3>
                <span className="text-sm px-3 py-1 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full font-medium">
                    {items.filter(i => i.status === "completed").length} of {items.length} Completed
                </span>
            </div>

            <motion.div
                className="relative border-l-2 border-slate-100 dark:border-slate-800 ml-3 space-y-8"
                variants={{
                    hidden: { opacity: 0 },
                    show: {
                        opacity: 1,
                        transition: { staggerChildren: 0.15 }
                    }
                }}
                initial="hidden"
                animate="show"
            >
                {items.map((item, index) => (
                    <motion.div
                        key={item.id}
                        variants={{
                            hidden: { opacity: 0, x: -20 },
                            show: { opacity: 1, x: 0 }
                        }}
                        className="relative pl-8"
                    >
                        {/* Timeline dot */}
                        <div className="absolute -left-[13px] top-1 bg-white dark:bg-slate-950 ring-4 ring-white dark:ring-slate-950 rounded-full">
                            {getIcon(item.type, item.status)}
                        </div>

                        <div className={`p-5 rounded-xl border transition-colors ${item.status === "completed"
                            ? "bg-emerald-50/50 border-emerald-100 dark:bg-emerald-900/10 dark:border-emerald-900/30"
                            : item.status === "in_progress"
                                ? "bg-indigo-50/50 border-indigo-100 dark:bg-indigo-900/10 dark:border-indigo-900/30 shadow-sm"
                                : "bg-white border-slate-100 dark:bg-slate-900 dark:border-slate-800"
                            }`}>
                            <div className="flex justify-between items-start mb-2">
                                <h4 className={`font-semibold ${item.status === "completed" ? "text-slate-500 line-through dark:text-slate-400" : "text-slate-900 dark:text-white"
                                    }`}>
                                    {item.title}
                                </h4>
                                <span className={`text-xs uppercase tracking-wider font-bold ${item.type === "payment" ? "text-emerald-500" : "text-indigo-500"
                                    }`}>
                                    {item.type}
                                </span>
                            </div>
                            <p className={`text-sm ${item.status === "completed" ? "text-slate-400 dark:text-slate-500" : "text-slate-600 dark:text-slate-400"
                                }`}>
                                {item.description}
                            </p>
                        </div>
                    </motion.div>
                ))}
            </motion.div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion } from "framer-motion";
import { Shield, Zap, Lock, FileText } from "lucide-react";

export function Shield3D() {
    return (
        <div className="relative mx-auto flex h-64 w-64 items-center justify-center perspective-[1000px] sm:h-80 sm:w-80">
            <div className="absolute inset-0 rounded-full bg-indigo-500/20 blur-[80px]" />

            <motion.div
                className="relative z-10 flex h-full w-full cursor-pointer items-center justify-center"
                initial={{ rotateY: -15, rotateX: 10 }}
                animate={{
                    rotateY: [0, 10, -10, 0],
                    rotateX: [0, -5, 5, 0],
                    y: [-5, 5, -5]
                }}
                transition={{
                    duration: 6,
                    repeat: Infinity,
                    repeatType: "reverse",
                    ease: "easeInOut"
                }}
                whileHover={{ scale: 1.05, rotateY: 0, rotateX: 0, transition: { duration: 0.2 } }}
                style={{ transformStyle: "preserve-3d" }}
            >
                {/* The glowing shield core */}
                <div className="absolute inset-0 flex items-center justify-center">
                    <Shield className="h-4/5 w-4/5 text-indigo-500/30 drop-shadow-[0_0_15px_rgba(99,102,241,0.5)]" strokeWidth={1} style={{ transform: "translateZ(-20px)" }} />
                </div>

                {/* Main Solid Shield */}
                <div className="absolute inset-0 flex items-center justify-center">
                    <Shield className="h-full w-full text-indigo-600 drop-shadow-2xl dark:text-indigo-400" strokeWidth={1.5} style={{ fill: "currentColor", fillOpacity: 0.1, transform: "translateZ(0px)" }} />
                </div>

                {/* Floating elements indicating AI and protection */}
                <motion.div
                    className="absolute -right-4 -top-4 flex h-12 w-12 items-center justify-center rounded-full border border-slate-200 bg-white shadow-xl dark:border-slate-800 dark:bg-slate-900"
                    style={{ transform: "translateZ(30px)" }}
                    animate={{ y: [0, -10, 0] }}
                    transition={{ duration: 4, repeat: Infinity, delay: 0.5 }}
                >
                    <Zap className="h-6 w-6 text-amber-500" />
                </motion.div>

                <motion.div
                    className="absolute -bottom-2 -left-2 flex h-14 w-14 items-center justify-center rounded-full border border-slate-200 bg-white shadow-xl dark:border-slate-800 dark:bg-slate-900"
                    style={{ transform: "translateZ(40px)" }}
                    animate={{ y: [0, 12, 0] }}
                    transition={{ duration: 5, repeat: Infinity, delay: 1 }}
                >
                    <Lock className="h-7 w-7 text-emerald-500" />
                </motion.div>

                <motion.div
                    className="absolute -right-8 bottom-12 flex h-10 w-10 items-center justify-center rounded-full border border-slate-200 bg-white shadow-xl dark:border-slate-800 dark:bg-slate-900"
                    style={{ transform: "translateZ(50px)" }}
                    animate={{ y: [0, -8, 0] }}
                    transition={{ duration: 3.5, repeat: Infinity, delay: 2 }}
                >
                    <FileText className="h-5 w-5 text-blue-500" />
                </motion.div>
            </motion.div>
        </div>
    );
}

"use client";

import React, { useCallback, useState } from "react";
import { useDropzone } from "react-dropzone";
import { motion, AnimatePresence } from "framer-motion";
import { UploadCloud, File, AlertCircle, CheckCircle2, Loader2, Shield } from "lucide-react";

interface UploadZoneProps {
    onUpload: (file: File) => void;
    isProcessing: boolean;
}

export function UploadZone({ onUpload, isProcessing }: UploadZoneProps) {
    const [error, setError] = useState<string | null>(null);

    const onDrop = useCallback((acceptedFiles: File[], fileRejections: any[]) => {
        setError(null);
        if (fileRejections.length > 0) {
            setError("Please upload a valid PDF document under 10MB.");
            return;
        }

        if (acceptedFiles.length > 0) {
            onUpload(acceptedFiles[0]);
        }
    }, [onUpload]);

    const { getRootProps, getInputProps, isDragActive, isDragReject } = useDropzone({
        onDrop,
        accept: {
            'application/pdf': ['.pdf']
        },
        maxSize: 10 * 1024 * 1024, // 10MB
        maxFiles: 1,
        disabled: isProcessing
    });

    return (
        <div className="w-full max-w-2xl mx-auto">
            <motion.div
                {...(getRootProps() as any)}
                className={`relative overflow-hidden rounded-2xl border-2 border-dashed p-12 text-center transition-colors
          ${isDragActive ? "border-indigo-500 bg-indigo-50/50 dark:bg-indigo-900/10" : "border-slate-300 bg-slate-50 hover:bg-slate-100 dark:border-slate-700 dark:bg-slate-900 dark:hover:bg-slate-800"}
          ${isDragReject ? "border-red-500 bg-red-50 dark:bg-red-900/10" : ""}
          ${isProcessing ? "opacity-70 cursor-not-allowed border-indigo-200 dark:border-indigo-800" : "cursor-pointer"}
        `}
                animate={{ scale: isDragActive ? 1.02 : 1 }}
                transition={{ type: "spring", stiffness: 300, damping: 20 }}
            >
                <input {...getInputProps()} />

                <div className="relative z-10 flex flex-col items-center justify-center space-y-4">
                    <AnimatePresence mode="popLayout">
                        {isProcessing ? (
                            <motion.div
                                key="processing"
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="flex items-center justify-center h-16 w-16 rounded-full bg-indigo-100 dark:bg-indigo-900/50"
                            >
                                <Loader2 className="h-8 w-8 animate-spin text-indigo-600 dark:text-indigo-400" />
                            </motion.div>
                        ) : isDragReject ? (
                            <motion.div
                                key="reject"
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="flex items-center justify-center h-16 w-16 rounded-full bg-red-100 dark:bg-red-900/50"
                            >
                                <AlertCircle className="h-8 w-8 text-red-600 dark:text-red-400" />
                            </motion.div>
                        ) : isDragActive ? (
                            <motion.div
                                key="active"
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="flex items-center justify-center h-16 w-16 rounded-full bg-indigo-200 dark:bg-indigo-800"
                            >
                                <File className="h-8 w-8 text-indigo-700 dark:text-indigo-300" />
                            </motion.div>
                        ) : (
                            <motion.div
                                key="idle"
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="flex items-center justify-center h-16 w-16 rounded-full bg-slate-200 dark:bg-slate-800"
                            >
                                <UploadCloud className="h-8 w-8 text-slate-600 dark:text-slate-400" />
                            </motion.div>
                        )}
                    </AnimatePresence>

                    <div className="space-y-1">
                        <h3 className="text-xl font-semibold text-slate-900 dark:text-white">
                            {isProcessing ? "Analyzing Document..." :
                                isDragReject ? "Invalid file type" :
                                    isDragActive ? "Drop your contract here" :
                                        "Upload your contract"}
                        </h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400">
                            {isProcessing ? "Our AI is currently scanning the document for risks." : "Drag and drop your PDF here, or click to browse files"}
                        </p>
                    </div>

                    <div className="text-xs text-slate-400 mt-4 flex items-center gap-1">
                        <Shield className="h-3 w-3" /> Secure, end-to-end encrypted upload
                    </div>
                </div>

                {/* Scanning Animation Overlay */}
                {isProcessing && (
                    <motion.div
                        className="absolute left-0 right-0 h-1 bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.8)] z-0"
                        initial={{ top: "0%" }}
                        animate={{ top: ["0%", "100%", "0%"] }}
                        transition={{ duration: 3, ease: "linear", repeat: Infinity }}
                    />
                )}
            </motion.div>

            {error && (
                <motion.p
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="mt-4 text-center text-sm font-medium text-red-500"
                >
                    {error}
                </motion.p>
            )}
        </div>
    );
}
